mapper.select:
SELECT 
FROM check_records_new
WHERE deleted = 0

    AND check_name LIKE CONCAT('%', #{checkName}, '%')


    AND check_date >= #{checkDateStart}


    AND check_date <= #{checkDateEnd}


    AND status = #{status}


    AND check_type = #{checkType}


    AND plan_id = #{planId}



    AND EXISTS (
        SELECT 1 FROM check_record_class_stats cs
        WHERE cs.record_id = check_records_new.id
        AND cs.class_id IN #{cid}
    )

ORDER BY check_date DESC, created_at DESC
